use std::thread;

fn main() {
    let mut handles = vec![];

    // Demonstrate that closures can capture and send data
    for i in 0..5 {
        handles.push(thread::spawn(move || {
            println!("Thread {} says hello", i);
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("All threads completed");
}
